firstAgent.answer:
agent 関数をインポートし、provider、instructions、オプションのパーソナリティ特性で構成します。最小限の例:

import { agent } from '@framers/agentos'

const myAgent = agent({
  provider: 'openai',
  instructions: 'あなたは親切なアシスタントです。',
  personality: { openness: 0.8, conscientiousness: 0.9 },
  memory: { enabled: true },
})

const reply = await myAgent.send('こんにちは!')
console.log(reply.text)
